render(() => {
    const [checked, setChecked] = React.useState(true);
    const handleChange = () => setChecked(!checked);

    const wrapper = {
        position: 'relative',
        borderRadius: '16px',
        width: '330px',
        height: '100px',
    };

    const image = {
        width: '100%',
        height: '100%',
        borderRadius: 'inherit',
        objectFit: 'cover',
    };

    const wrapperButton = {
        position: 'absolute',
        display: 'flex',
        inset: '0px',
        padding: '20px',
        justifyContent: 'space-between',
    };

    return (
        <>
            <div style={wrapper}>
                <img style={image} src='./images/buttonBlur.png' />
                <div style={wrapperButton}>
                    <Button
                        view='primary'
                        colors='inverted'
                        disabled={true}
                        allowBackdropBlur={checked}
                    >
                        Disabled
                    </Button>
                    <Button view='secondary' colors='inverted' allowBackdropBlur={checked}>
                        Secondary
                    </Button>
                </div>
            </div>

            <Row align='middle'>
                <Switch label='Включить размытие' checked={checked} onChange={handleChange} />
            </Row>
        </>
    );
});

render(() => {
    const [loading, setLoading] = React.useState(false);
    const [loadTimeout, setLoadTimeout] = React.useState('30');
    const timeoutId = React.useRef();

    const handleClick = () => {
        setLoading(true);

        clearTimeout(timeoutId.current);

        timeoutId.current = setTimeout(() => {
            setLoading(false);
        }, Number(loadTimeout));
    };

    const handleTimeoutChange = (_, { value }) => {
        clearTimeout(timeoutId.current);
        setLoading(false);
        setLoadTimeout(value);
    };

    return (
        <>
            <Button
                view='primary'
                loading={loading}
                onClick={handleClick}
                breakpoint={BREAKPOINT}
                block={isMobile()}
            >
                Отправить запрос
            </Button>

            <Gap size={24} />

            <RadioGroup value={loadTimeout} onChange={handleTimeoutChange}>
                <Radio value='30' label='Быстрый запрос (30ms)' />
                <Radio value='1500' label='Долгий запрос (1500ms)' />
            </RadioGroup>
        </>
    );
});
